const fs = require('fs');
const input = fs.readFileSync(0,'utf-8').trim().split(/\s+/);
let idx = 0;
function Node(data){this.data=data;this.next=null;}
function reverseRecursive(head){
    if(head===null||head.next===null) return head;
    const rest = reverseRecursive(head.next);
    head.next.next = head;
    head.next = null;
    return rest;
}
const T = Number(input[idx++]);
let outputs = [];
for(let t=0;t<T;t++){
    const n = Number(input[idx++]);
    if(n===0){outputs.push('NULL'); continue;}
    let head=null, tail=null;
    for(let i=0;i<n;i++){
        const val = Number(input[idx++]);
        const nd = new Node(val);
        if(head===null) head=nd; else tail.next=nd;
        tail=nd;
    }
    head = reverseRecursive(head);
    let arr=[];
    for(let cur=head;cur!==null;cur=cur.next) arr.push(String(cur.data));
    outputs.push(arr.join(' '));
}
